const items = $input.all();

let inventoryData = null;
let requestData = null;
for (const item of items) {
    const data = item.json.data;
    if (data && data.includes('商品ID')) {
        inventoryData = data;
    } else if (data && (data.includes('补货') || data.includes('笔记本') || data.includes('橡皮'))) {
        requestData = data;
    }
}

if (!inventoryData) throw new Error('无法获取库存表数据');
if (!requestData) throw new Error('无法获取补货请求数据');

// 解析库存 CSV
const lines = inventoryData.trim().split('\n');
const headers = lines[0].split(',');
const inventoryMap = {};
for (let i = 1; i < lines.length; i++) {
    const values = lines[i].split(',');
    const id = values[0].trim();
    const name = values[1].trim();
    const stock = parseInt(values[2].trim(), 10);
    inventoryMap[name] = { id, name, stock };
}

// 解析补货请求
const requestLines = requestData.split('\n').filter(l => l.trim().length > 0);
const updates = [];
const productNames = Object.keys(inventoryMap);

for (const line of requestLines) {
    let matchedProduct = null;
    for (const name of productNames) {
        if (line.includes(name)) {
            matchedProduct = name;
            break;
        }
    }
    if (!matchedProduct) {
        updates.push({ line, status: '未知商品' });
        continue;
    }
    const qtyMatch = line.match(/(\d+)/);
    if (!qtyMatch) {
        updates.push({ product: matchedProduct, status: '无法提取数量' });
        continue;
    }
    const qty = parseInt(qtyMatch[1], 10);
    if (inventoryMap[matchedProduct]) {
        inventoryMap[matchedProduct].stock += qty;
        updates.push({ product: matchedProduct, added: qty, newStock: inventoryMap[matchedProduct].stock });
    } else {
        updates.push({ product: matchedProduct, added: qty, status: 'unknown' });
    }
}

// 生成新的 CSV 内容
let newCsv = headers.join(',') + '\n';
for (const key in inventoryMap) {
    const item = inventoryMap[key];
    newCsv += `${item.id},${item.name},${item.stock}\n`;
}

return {
    newCsv: newCsv.trim(),
    updates: updates
};

const newCsv = $json.newCsv;
const base64Data = Buffer.from(newCsv, 'utf-8').toString('base64');
return {
    json: {},
    binary: {
        data: {
            data: base64Data,
            fileName: 'inventory.csv',
            mimeType: 'text/csv',
            fileSize: newCsv.length
        }
    }
};
